def install():
    dest = os.path.join(os.path.expanduser("~"), "loterias-caixa")
    print(f"Instalando em: {dest}")
    for rel_path, encoded in FILES.items():
        full = os.path.join(dest, rel_path.replace("/", os.sep))
        os.makedirs(os.path.dirname(full), exist_ok=True)
        data = zlib.decompress(base64.b64decode(encoded))
        with open(full, "wb") as f:
            f.write(data)
    os.makedirs(os.path.join(dest, "data"), exist_ok=True)
    print("Arquivos extraídos. Instalando dependências...")
    subprocess.run([sys.executable, "-m", "pip", "install",
                    "flask", "openpyxl", "rich", "questionary", "-q"], check=True)
    print()
    print("=" * 50)
    print("  Instalação concluída!")
    print(f"  Pasta: {dest}")
    print()
    print("  Para iniciar o sistema:")
    print(f"    cd {dest}")
    print("    python main.py")
    print()
    print("  O browser abrirá automaticamente em:")
    print("    http://localhost:5000")
    print("=" * 50)

if __name__ == "__main__":
    install()

